options.customCss:
:root {
  /* Colors - Palette dérivée de #0e0c3a */
  --chat--color--primary: #0e0c3a;
  --chat--color--primary-shade-50: #0b0a2e;
  --chat--color--primary--shade-100: #080722;
  --chat--color--secondary: #4f46e5;
  --chat--color-secondary-shade-50: #4338ca;
  --chat--color-white: #fff;
  --chat--color-light: #f0f0f8;
  --chat--color-light-shade-50: #e2e2f0;
  --chat--color-light-shade-100: #c5c5de;
  --chat--color-medium: #d0d0e8;
  --chat--color-dark: #0e0c3a;
  --chat--color-disabled: #c5c5de;
  --chat--color-typing: #3d3a70;

  /* Base Layout */
  --chat--spacing: 1rem;
  --chat--border-radius: 0.25rem;
  --chat--transition-duration: 0.15s;
  --chat--font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen-Sans, Ubuntu, Cantarell, 'Helvetica Neue', sans-serif;

  /* Window Dimensions */
  --chat--window--width: 400px;
  --chat--window--height: 600px;
  --chat--window--bottom: var(--chat--spacing);
  --chat--window--right: var(--chat--spacing);
  --chat--window--z-index: 9999;
  --chat--window--border: 1px solid var(--chat--color-light-shade-50);
  --chat--window--border-radius: var(--chat--border-radius);
  --chat--window--margin-bottom: var(--chat--spacing);

  /* Header Styles */
  --chat--header-height: auto;
  --chat--header--padding: var(--chat--spacing);
  --chat--header--background: #0e0c3a;
  --chat--header--color: #f0f0f8;
  --chat--header--border-top: none;
  --chat--header--border-bottom: 1px solid rgba(255, 255, 255, 0.1);
  --chat--header--border-left: none;
  --chat--header--border-right: none;
  --chat--heading--font-size: 2em;
  --chat--subtitle--font-size: inherit;
  --chat--subtitle--line-height: 1.8;

  /* Message Styles */
  --chat--message--font-size: 1rem;
  --chat--message--padding: var(--chat--spacing);
  --chat--message--border-radius: var(--chat--border-radius);
  --chat--message-line-height: 1.5;
  --chat--message--margin-bottom: calc(var(--chat--spacing) * 1);
  --chat--message--bot--background: #ffffff;
  --chat--message--bot--color: #0e0c3a;
  --chat--message--bot--border: none;
  --chat--message--user--background: #4f46e5;
  --chat--message--user--color: #ffffff;
  --chat--message--user--border: none;
  --chat--message--pre--background: rgba(14, 12, 58, 0.06);
  --chat--messages-list--padding: var(--chat--spacing);

  /* Toggle Button */
  --chat--toggle--size: 64px;
  --chat--toggle--width: var(--chat--toggle--size);
  --chat--toggle--height: var(--chat--toggle--size);
  --chat--toggle--border-radius: 50%;
  --chat--toggle--background: #0e0c3a;
  --chat--toggle--hover--background: #0b0a2e;
  --chat--toggle--active--background: #080722;
  --chat--toggle--color: #ffffff;

  /* Input Area */
  --chat--textarea--height: 50px;
  --chat--textarea--max-height: 30rem;
  --chat--input--font-size: inherit;
  --chat--input--border: 0;
  --chat--input--border-radius: 0;
  --chat--input--padding: 0.8rem;
  --chat--input--background: #ffffff;
  --chat--input--text-color: #0e0c3a;
  --chat--input--line-height: 1.5;
  --chat--input--placeholder--font-size: var(--chat--input--font-size);
  --chat--input--border-active: 0;
  --chat--input--left--panel--width: 2rem;

  /* Button Styles */
  --chat--button--padding: calc(var(--chat--spacing) * 5 / 8) var(--chat--spacing);
  --chat--button--border-radius: var(--chat--border-radius);
  --chat--button--font-size: 1rem;
  --chat--button--line-height: 1;
  --chat--button--color--primary: #f0f0f8;
  --chat--button--background--primary: #4f46e5;
  --chat--button--border--primary: none;
  --chat--button--color--primary--hover: #f0f0f8;
  --chat--button--background--primary--hover: #4338ca;
  --chat--button--border--primary--hover: none;
  --chat--button--color--primary--disabled: #f0f0f8;
  --chat--button--background--primary--disabled: #a5a1f0;
  --chat--button--border--primary--disabled: none;
  --chat--button--color--secondary: #f0f0f8;
  --chat--button--background--secondary: hsl(0, 0%, 58%);
  --chat--button--border--secondary: none;
  --chat--button--color--secondary--hover: #f0f0f8;
  --chat--button--background--secondary--hover: hsl(0, 0%, 51%);
  --chat--button--border--secondary--hover: none;
  --chat--button--color--secondary--disabled: #f0f0f8;
  --chat--button--background--secondary--disabled: hsl(0, 0%, 78%);
  --chat--button--border--secondary--disabled: none;
  --chat--close--button--color-hover: #4f46e5;

  /* Send and File Buttons */
  --chat--input--send--button--background: #ffffff;
  --chat--input--send--button--color: #4f46e5;
  --chat--input--send--button--background-hover: #e2e2f0;
  --chat--input--send--button--color-hover: #4338ca;
  --chat--input--file--button--background: #ffffff;
  --chat--input--file--button--color: #4f46e5;
  --chat--input--file--button--background-hover: #ffffff;
  --chat--input--file--button--color-hover: #4338ca;
  --chat--files-spacing: 0.25rem;

  /* Body and Footer */
  --chat--body--background: #f0f0f8;
  --chat--footer--background: #f0f0f8;
  --chat--footer--color: #0e0c3a;
}


/* You can override any class styles, too. Right-click inspect in Chat UI to find class to override. */
.chat-message {
  max-width: 50%;
}

parameters.jsCode:
const expected = 'REDACTED_Emma_SECRET';

const headers =
  $json?.headers ??
  $input.first()?.json?.headers ??
  {};

const got =
  headers['x-emma-secret'] ||
  headers['X-Emma-Secret'] ||
  $json?.emmaSecret ||
  $input.first()?.json?.emmaSecret;

if (got !== expected) {
  throw new Error('Unauthorized: secret manquant ou invalide');
}

return $input.all();

// Filtre bruit : ne laisse passer que les questions avec une substance métier réelle.
// Même logique que le rapport hebdo (LOW_SIGNAL_EXACT + règles courtes).
const LOW_SIGNAL = new Set([
  'ensuite','et ensuite','et apres','apres','alors','donc','voila',
  'cherche bien','cherche encore','regarde bien','tu peux chercher',
  'reflechis','continue','vas y','vasy',
  'oui','non','ok','okay','merci','merci beaucoup',
  'd accord','dacord','ah ok','super','parfait','top','nickel','niquel','cool',
  'bah','ben','euh','hm','hmm','ouais','nan','na','lol','haha','gg',
  'hello','bonjour','salut','hey','coucou',
]);

function normalize(s) {
  return String(s)
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[''`´]/g, ' ')
    .replace(/[^\w\s]/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const question = $input.first()?.json?.chatInput ||
  $('When chat message received').item?.json?.chatInput || '';

const k = normalize(question);
const words = k.split(/\s+/).filter(Boolean);

// Exclure : vide, trop court, dans la liste, ou moins de 4 mots sans chiffre ni terme technique
if (!k || k.length < 8 || LOW_SIGNAL.has(k) || words.length < 3) {
  return [];
}

return $input.all();
